soal.pertanyaan:
Perhatikan kode berikut:

// file: utilitas.js
function formatTanggal(date) {
  return date.toLocaleDateString('id-ID');
}
module.exports = formatTanggal;

// file: app.js
const format = require('./utilitas');
console.log(format(new Date()));

Apa yang akan terjadi dan sistem module apa yang digunakan?

Perhatikan kode EventEmitter berikut:

const emitter = new EventEmitter();
emitter.on('data', (val) => console.log('A:', val));
emitter.once('data', (val) => console.log('B:', val));
emitter.on('data', (val) => console.log('C:', val));

emitter.emit('data', 1);
emitter.emit('data', 2);

Apa output yang dihasilkan?

